func goTypeForSchemaType(schemaType ast.SchemaType, nullable bool) goTypeInfo {
	switch t := schemaType.(type) {
	case *ast.ArraySchemaType:
		item := goTypeForSchemaType(t.Item, false)
		return goTypeInfo{
